  /**
   * PrivacyGuard — Masking Engine
   *
   * Transforms detected sensitive values into safe, human-readable masked forms.
   * Pure JavaScript — no browser API dependencies.
   *
   * Each masking strategy preserves enough structure for the user to recognise
   * WHAT was detected, while redacting the sensitive payload.
   *
   * @module masker
   */

  // ─── Per-Rule Masking Strategies ────────────────────────────────

  /**
   * Credit/Debit Card → "4111 **** **** 1111"
   * Strip non-digits, show first 4 + last 4, mask middle.
   */
  function maskCreditCard(text) {
    const digits = text.replace(/\D/g, '');
    if (digits.length < 8) return '*'.repeat(text.length); // fallback for very short
    const first4 = digits.slice(0, 4);
    const last4 = digits.slice(-4);
    return `${first4} **** **** ${last4}`;
  }

  /**
   * US SSN → "***-**-6789"
   * Mask area + group, show serial (last 4).
   */
  function maskSSN(text) {
    const digits = text.replace(/\D/g, '');
    if (digits.length < 4) return '***-**-****';
    return `***-**-${digits.slice(-4)}`;
  }

  /**
   * Aadhaar → "**** **** 0123"
   * Mask first 8 digits, show last 4.
   */
  function maskAadhaar(text) {
    const digits = text.replace(/\D/g, '');
    if (digits.length < 4) return '**** **** ****';
    return `**** **** ${digits.slice(-4)}`;
  }

  /**
   * PAN Card → "ABCDE****F"
   * Show first 5 chars + last 1 char, mask middle 4 digits.
   */
  function maskPAN(text) {
    if (text.length < 6) return '*'.repeat(text.length);
    return `${text.slice(0, 5)}****${text.slice(-1)}`;
  }

  /**
   * Email → "a****@****.com"
   * Show first char of local part, mask rest.
   * Mask domain name, preserve TLD.
   */
  function maskEmail(text) {
    const atIdx = text.indexOf('@');
    if (atIdx < 0) return '****@****'; // malformed fallback

    const local = text.slice(0, atIdx);
    const domain = text.slice(atIdx + 1);

    // Extract TLD (last dot-separated segment)
    const lastDot = domain.lastIndexOf('.');
    const tld = lastDot >= 0 ? domain.slice(lastDot + 1) : domain;

    const maskedLocal = local.length > 0 ? local[0] + '****' : '****';
    return `${maskedLocal}@****.${tld}`;
  }

  /**
   * Phone → "+91 ***** **210"
   * Preserve country code prefix (+XX) and non-digit formatting chars.
   * Mask all digits except the last 3.
   */
  function maskPhone(text) {
    // Extract optional country code prefix: +91, +1, etc.
    const prefixMatch = text.match(/^(\+\d{1,3}[\s\-]?)/);
    const prefix = prefixMatch ? prefixMatch[0] : '';
    const rest = text.slice(prefix.length);

    // Count total digits in the remaining portion
    const digits = rest.replace(/\D/g, '');
    const visibleCount = Math.min(3, digits.length);
    const maskCount = digits.length - visibleCount;

    // Walk through rest: mask digits left-to-right, preserve non-digits in place
    let digitIndex = 0;
    let masked = '';
    for (const ch of rest) {
      if (/\d/.test(ch)) {
        masked += digitIndex < maskCount ? '*' : ch;
        digitIndex++;
      } else {
        masked += ch; // preserve spaces, dashes, parens
      }
    }

    return prefix + masked;
  }

  /**
   * API Key → "sk-****lMNO"
   * Preserve known prefix (sk-, ghp_, etc.), mask middle, show last 4 chars.
   */
  function maskAPIKey(text) {
    const prefixMatch = text.match(/^(sk-|pk_|rk_|ghp_|glpat-|AIza)/i);
    const prefix = prefixMatch ? prefixMatch[0] : '';
    const last4 = text.length > 4 ? text.slice(-4) : '';
    return `${prefix}****${last4}`;
  }

  /**
   * Password in Context → "password=********"
   * Preserve the keyword + separator, fully mask the value.
   */
  function maskPassword(text) {
    // Match: keyword + optional whitespace + separator + optional quote
    const separatorMatch = text.match(
      /^((?:password|passwd|pwd|pass)\s*[=:]\s*['"]?)/i
    );
    if (separatorMatch) {
      return separatorMatch[0] + '********';
    }
    return '********';
  }

  /**
   * DB Connection String → "postgres://admin:****@prod-db:5432/app"
   * Only mask the password segment between user: and @host.
   */
  function maskDBConn(text) {
    // protocol://user:PASSWORD@rest  →  protocol://user:****@rest
    return text.replace(/:\/\/([^:\s]+):([^@\s]+)@/, '://$1:****@');
  }

  /**
   * Bearer Token → "Bearer ****abc123"
   * Show "Bearer " prefix + last 6 chars, mask the rest.
   */
  function maskBearer(text) {
    // Strip the "Bearer " prefix and get the token body
    const tokenMatch = text.match(/^(Bearer\s+)(.+)$/);
    if (!tokenMatch) return 'Bearer ****';

    const prefix = tokenMatch[1]; // "Bearer "
    const token = tokenMatch[2];
    const last6 = token.length > 6 ? token.slice(-6) : token;
    return `${prefix}****${last6}`;
  }


  // ─── Strategy Router ────────────────────────────────────────────

  /** Map from ruleId → masking function */
  const MASK_STRATEGY = {
    'CC-01': maskCreditCard,
    'SSN-01': maskSSN,
    'AADHAAR-01': maskAadhaar,
    'PAN-01': maskPAN,
    'EMAIL-01': maskEmail,
    'PHONE-01': maskPhone,
    'APIKEY-01': maskAPIKey,
    'PWD-01': maskPassword,
    'DBCONN-01': maskDBConn,
    'BEARER-01': maskBearer,
  };


  // ─── Public API ─────────────────────────────────────────────────

  /**
   * Mask a single matched value using the rule-specific strategy.
   *
   * @param {string} matchedText — The raw text that was matched by the regex.
   * @param {string} ruleId      — The rule ID from the detection result (e.g. 'CC-01').
   * @returns {string} — The masked representation.
   */
  function maskValue(matchedText, ruleId) {
    if (!matchedText || typeof matchedText !== 'string') return '';

    const strategy = MASK_STRATEGY[ruleId];
    if (strategy) {
      return strategy(matchedText);
    }

    // Fallback: mask entire value if no strategy found
    return '*'.repeat(matchedText.length);
  }

  /**
   * Apply masking to ALL detections within a full text string.
   *
   * Replaces each detected segment with its masked equivalent.
   * Processes detections RIGHT → LEFT to preserve character indices.
   *
   * @param {string}            text       — The original full text.
   * @param {DetectionResult[]} detections — Results from scanForPII().
   * @returns {string} — The fully masked text.
   */
  function maskAll(text, detections) {
    if (!text || typeof text !== 'string') return text ?? '';
    if (!detections || detections.length === 0) return text;

    // Sort by startIndex DESCENDING — so we replace from right to left
    // This keeps earlier indices valid as we splice the string.
    const sorted = [...detections].sort((a, b) => b.startIndex - a.startIndex);

    let result = text;
    for (const det of sorted) {
      const masked = maskValue(det.matchText, det.ruleId);
      result = result.slice(0, det.startIndex) + masked + result.slice(det.endIndex);
    }

    return result;
  }


  // ─── Exports ────────────────────────────────────────────────────


  // ════════════════════════════════════════════════════════════
  // Source: src/utils/storage.js
  // ════════════════════════════════════════════════════════════

  /**
   * PrivacyGuard — Storage Abstraction Layer
   *
   * Promise-based wrapper around chrome.storage.local for:
   *   - Detection log (FIFO, max 50 entries)
   *   - Domain allowlist (exact match)
   *   - Extension enabled/disabled toggle
   *
   * MV3's chrome.storage.local natively returns Promises.
   * All functions are safe against empty/missing storage.
   *
   * @module storage
   */


  // ─── Constants ──────────────────────────────────────────────────
  const MAX_DETECTIONS = 50;


  // ─── Low-Level Helpers ──────────────────────────────────────────

  /**
   * Read a value from chrome.storage.local.
   * Returns `defaultValue` if the key doesn't exist or storage is unavailable.
   *
   * @param {string} key
   * @param {*}      defaultValue
   * @returns {Promise<*>}
   */
  async function getFromStorage(key, defaultValue = null) {
    try {
      const result = await chrome.storage.local.get(key);
      return result[key] !== undefined ? result[key] : defaultValue;
    } catch (err) {
      console.warn('[PrivacyGuard] Storage read error:', err);
      return defaultValue;
    }
  }

  /**
   * Write a value to chrome.storage.local.
   *
   * @param {string} key
   * @param {*}      value
   * @returns {Promise<void>}
   */
  async function setToStorage(key, value) {
    try {
      await chrome.storage.local.set({ [key]: value });
    } catch (err) {
      console.warn('[PrivacyGuard] Storage write error:', err);
    }
  }


  // ─── Extension Toggle ───────────────────────────────────────────

  /**
   * Set the extension enabled/disabled state.
   *
   * @param {boolean} state — true = enabled, false = disabled.
   * @returns {Promise<void>}
   */
  async function setEnabled(state) {
    await setToStorage(STORAGE_KEYS.ENABLED, !!state);
  }

  /**
   * Check if the extension is enabled.
   * Defaults to `true` if not previously set.
   *
   * @returns {Promise<boolean>}
   */
  async function isEnabled() {
    return await getFromStorage(STORAGE_KEYS.ENABLED, true);
  }


  // ─── Domain Allowlist ───────────────────────────────────────────

  /**
   * Get the full allowlist array.
   *
   * @returns {Promise<string[]>}
   */
  async function getAllowlist() {
    return await getFromStorage(STORAGE_KEYS.ALLOWLIST, []);
  }

  /**
   * Add a domain to the allowlist.
   * Normalizes to lowercase. Prevents duplicates.
   *
   * @param {string} domain — e.g. "chatgpt.com"
   * @returns {Promise<void>}
   */
  async function addToAllowlist(domain) {
    if (!domain || typeof domain !== 'string') return;

    const normalized = domain.toLowerCase().trim();
    const list = await getAllowlist();

    // Prevent duplicates
    if (list.includes(normalized)) return;

    list.push(normalized);
    await setToStorage(STORAGE_KEYS.ALLOWLIST, list);
  }

  /**
   * Remove a domain from the allowlist.
   *
   * @param {string} domain
   * @returns {Promise<void>}
   */
  async function removeFromAllowlist(domain) {
    if (!domain || typeof domain !== 'string') return;

    const normalized = domain.toLowerCase().trim();
    const list = await getAllowlist();
    const filtered = list.filter(d => d !== normalized);

    await setToStorage(STORAGE_KEYS.ALLOWLIST, filtered);
  }

  /**
   * Check if a domain is in the allowlist (exact match).
   *
   * @param {string} domain
   * @returns {Promise<boolean>}
   */
  async function isAllowed(domain) {
    if (!domain || typeof domain !== 'string') return false;

    const normalized = domain.toLowerCase().trim();
    const list = await getAllowlist();

    return list.includes(normalized);
  }


  // ─── Detection Log ──────────────────────────────────────────────

  /**
   * Add a detection entry to the log.
   *
   * Entry shape:
   *   {
   *     id: string,         — Unique ID (generated if missing)
   *     domain: string,     — The domain where PII was detected
   *     category: string,   — PAYMENT | PII | CREDENTIAL
   *     severity: string,   — LOW | MEDIUM | HIGH | CRITICAL
   *     ruleId: string,     — The rule that fired (e.g. "CC-01")
   *     maskedValue: string, — The masked representation
   *     timestamp: number   — Unix timestamp (generated if missing)
   *   }
   *
   * Enforces FIFO: oldest entries are removed when limit (50) is exceeded.
   *
   * @param {object} entry
   * @returns {Promise<void>}
   */
  async function addDetection(entry) {
    if (!entry || typeof entry !== 'object') return;

    // Ensure required fields have defaults
    const record = {
      id: entry.id || generateId(),
      domain: entry.domain || 'unknown',
      category: entry.category || 'UNKNOWN',
      severity: entry.severity || 'MEDIUM',
      ruleId: entry.ruleId || '',
      maskedValue: entry.maskedValue || '',
      timestamp: entry.timestamp || Date.now(),
    };

    const log = await getFromStorage(STORAGE_KEYS.DETECTIONS, []);

    // Add new entry at the front (newest first)
    log.unshift(record);

    // Trim to max size (FIFO — drop oldest from the end)
    if (log.length > MAX_DETECTIONS) {
      log.length = MAX_DETECTIONS;
    }

    await setToStorage(STORAGE_KEYS.DETECTIONS, log);
  }

  /**
   * Retrieve recent detection entries.
   *
   * @param {number} limit — Max number of entries to return (default 10).
   * @returns {Promise<object[]>} — Newest first.
   */
  async function getDetections(limit = 10) {
    const log = await getFromStorage(STORAGE_KEYS.DETECTIONS, []);
    return log.slice(0, Math.max(0, limit));
  }

  /**
   * Clear all detection history.
   *
   * @returns {Promise<void>}
   */
  async function clearDetections() {
    await setToStorage(STORAGE_KEYS.DETECTIONS, []);
  }

  /**
   * Get the total count of stored detections.
   *
   * @returns {Promise<number>}
   */
  async function getDetectionCount() {
    const log = await getFromStorage(STORAGE_KEYS.DETECTIONS, []);
    return log.length;
  }


  // ─── Utilities ──────────────────────────────────────────────────

  /**
   * Generate a short unique ID for detection entries.
   * Uses timestamp + random suffix for collision avoidance.
   *
   * @returns {string}
   */
  function generateId() {
    const ts = Date.now().toString(36);
    const rand = Math.random().toString(36).slice(2, 6);
    return `${ts}-${rand}`;
  }


  // ─── Exports ────────────────────────────────────────────────────


  // ════════════════════════════════════════════════════════════
  // Source: src/detection/llmClassifier.js
  // ════════════════════════════════════════════════════════════

  /**
   * PrivacyGuard — LLM Classifier (Content-side)
   *
   * Implements the hybrid detection fallback system.
   * Sends ambiguous, sufficiently long text to the background LLM worker
   * ONLY IF it's on an AI domain and regex missed it.
   * Ensures text is pre-masked and truncated before leaving the DOM world.
   *
   * @module llmClassifier
   */




  const TIMEOUT_MS = 2000;
  const MIN_LENGTH = 50;
  const MAX_LENGTH = 2000;
  const CONFIDENCE_THRESHOLD = 0.75;

  /**
   * Pre-masks text by replacing all regex PII matches with [REDACTED].
   * @param {string} text
   * @returns {string}
   */
  function preMaskText(text) {
    let masked = text;
    const piiResults = scanForPII(text);

    if (piiResults.length === 0) return masked;

    // Process from end to start to avoid index shifting
    const sorted = [...piiResults].sort((a, b) => b.startIndex - a.startIndex);

    for (const r of sorted) {
      masked =
        masked.slice(0, r.startIndex) +
        '[REDACTED]' +
        masked.slice(r.endIndex);
    }

    return masked;
  }

  /**
   * Determines if a piece of text requires an LLM classification,
   * pre-masks it, enforces timeout, and sends to the background.
   *
   * @param {string} text - The raw text from the input field
   * @param {string} domain - Current location.hostname
   * @returns {Promise<object|null>} - Returns matched category data or null
   */
  async function classifyWithLLM(text, domain) {
    if (!text || typeof text !== 'string') return null;

    // 1. Decision Logic Constraints
    if (text.length < MIN_LENGTH) return null;

    const isAiDomain = AI_DOMAINS.some(aiDomain => domain.includes(aiDomain));
    if (!isAiDomain) return null;

    const injectionResults = scanForInjection(text);
    if (injectionResults.length > 0) return null;

    const piiResults = scanForPII(text);
    if (piiResults.length > 0) return null;

    // 2. Pre-masking & Truncation (Safety)
    // Even if piiResults was 0, it is best practice to run safety masking 
    // in case logic changes above to permit partial detection overlaps.
    let safeText = preMaskText(text);

    if (safeText.length > MAX_LENGTH) {
      safeText = safeText.slice(0, MAX_LENGTH);
    }

    // 3. Delegate to Background via Messaging with Timeout
    const fetchPromise = new Promise((resolve) => {
      try {
        chrome.runtime.sendMessage(
          {
            type: 'PG_LLM_CLASSIFY',
            text: safeText
          },
          (response) => {
            if (chrome.runtime.lastError || !response) {
              resolve(null);
            } else {
              resolve(response);
            }
          }
        );
      } catch (err) {
        resolve(null); // Context invalidated
      }
    });

    const timeoutPromise = new Promise((resolve) => {
      setTimeout(() => resolve(null), TIMEOUT_MS);
    });

    try {
      const result = await Promise.race([fetchPromise, timeoutPromise]);

      // 4. Response handling
      if (!result || !result.category || result.category === 'NONE') {
        return null;
      }

      if (result.confidence >= CONFIDENCE_THRESHOLD) {
        return {
          ruleId: 'LLM-01',
          category: result.category,
          severity: result.category === 'INJECTION' ? 'INJECTION' : 'HIGH', // default mapped severity
          matchText: text, // Cannot map back exact substring, flag entire field (or pre-mask copy)
          description: result.reason || 'Flagged by AI analysis',
          confidence: result.confidence
        };
      }
    } catch (error) {
      console.error('[PrivacyGuard] LLM Classifier error:', error);
    }

    return null;
  }


